 {"id": "franken_networkx-graphtodigraph", "title": "REVIEW: [HIGH] DiGraph constructor drops reverse edges on undirected source", "description": "fnx.DiGraph(undirected_graph) returned only forward edges. Python _copy_constructor_graph_source used source.edges which yields only forward for undirected. Broke second_order_centrality on weighted paths with Singular matrix LinAlgError. Fixed by expanding undirected to directed when target is directed.", "status": "closed", "priority": 2, "issue_type": "bug", "created_at": "2026-04-24T11:44:05.000000000Z", "created_by": "cc-networkx", "updated_at": "2026-04-24T11:44:05.000000000Z", "closed_at": "2026-04-24T11:44:05.000000000Z", "close_reason": "expand_undirected_to_directed branch", "source_repo": ".", "compaction_level": 0, "original_size": 0}
 {"id": "franken_networkx-dagkw", "title": "REVIEW: [LOW] is_directed_acyclic_graph / transitive_closure / transitive_reduction used g not G", "description": "Rust bindings named first parameter lowercase g. Kwarg-style fnx.is_directed_acyclic_graph(G=d) TypeErrored. Added Python wrappers.", "status": "closed", "priority": 4, "issue_type": "bug", "created_at": "2026-04-24T11:47:19.000000000Z", "created_by": "cc-networkx", "updated_at": "2026-04-24T11:47:19.000000000Z", "closed_at": "2026-04-24T11:47:19.000000000Z", "close_reason": "Python wrappers", "source_repo": ".", "compaction_level": 0, "original_size": 0}
 {"id": "franken_networkx-treekw", "title": "REVIEW: [LOW] tree algorithms used g + default=1.0 vs nx G + default=1", "description": "minimum/maximum_spanning_edges/branching/arborescence, random_spanning_tree, partition_spanning_tree all used lowercase g first param and the branching/arborescence family used default=1.0 where nx uses default=1. Kwarg-style drop-in calls TypeErrored on G=. Added Python wrappers with nx-matching signatures.", "status": "closed", "priority": 4, "issue_type": "bug", "created_at": "2026-04-24T11:49:57.000000000Z", "created_by": "cc-networkx", "updated_at": "2026-04-24T11:49:57.000000000Z", "closed_at": "2026-04-24T11:49:57.000000000Z", "close_reason": "Python wrappers", "source_repo": ".", "compaction_level": 0, "original_size": 0}
+{"id": "franken_networkx-sp6kw", "title": "REVIEW: [LOW] from_sparse6_bytes used bytes_in instead of nx string parameter name", "description": "fnx.from_sparse6_bytes(string=b\":Cca\") TypeErrored because fnx named the param bytes_in while nx uses string (asymmetric with from_graph6_bytes which uses bytes_in on both). Renamed to match nx exactly.", "status": "closed", "priority": 4, "issue_type": "bug", "created_at": "2026-04-24T11:56:43.000000000Z", "created_by": "cc-networkx", "updated_at": "2026-04-24T11:56:43.000000000Z", "closed_at": "2026-04-24T11:56:43.000000000Z", "close_reason": "Param rename to match nx", "source_repo": ".", "compaction_level": 0, "original_size": 0}
+{"id": "franken_networkx-multikeyrt", "title": "REVIEW: [MEDIUM] MultiGraph round-trip through node_link_data / _from_nx_graph lost string keys", "description": "MultiGraph with edges keyed by non-integer values (strings, tuples) round-tripped through fnx.node_link_data/graph or fnx.readwrite._from_nx_graph would lose the original keys \u2014 fnx reassigned fresh integer keys. The Rust binding now accepts arbitrary keys directly, so removed the non-int fallback and preserve nx keys verbatim. Regression-visible: fnx.node_link_graph(data) now returns edges with original string keys instead of [0, 1, ...].", "status": "closed", "priority": 3, "issue_type": "bug", "created_at": "2026-04-24T11:56:43.000000000Z", "created_by": "cc-networkx", "updated_at": "2026-04-24T11:56:43.000000000Z", "closed_at": "2026-04-24T11:56:43.000000000Z", "close_reason": "Remove non-int fallback; Rust MultiGraph binding now accepts arbitrary keys", "source_repo": ".", "compaction_level": 0, "original_size": 0}
